// =================================================================
// PHẦN 2: LOGIC ĐỒNG BỘ DỮ LIỆU
// =================================================================
console.log("%c [Auto-LMS] Đang đồng bộ dữ liệu... ", "background: #1890ff; color: white; padding: 5px;");

// Lấy dữ liệu cũ trong máy (nếu có) và trộn với dữ liệu nạp sẵn
let localData = JSON.parse(localStorage.getItem('quiz_answers') || '[]');
let mergedData = [...PRELOADED_DATA, ...localData];

// Lọc bỏ các câu trùng lặp (nếu có) để không làm nặng máy
let uniqueData = Array.from(new Map(mergedData.map(item => [item.question, item])).values());
localStorage.setItem('quiz_answers', JSON.stringify(uniqueData));

console.log(`%c 📦 Đã nạp thành công! Kho hiện có ${uniqueData.length} câu. `, "color: #52c41a; font-weight: bold;");


// =================================================================
// PHẦN 3: LOGIC GỢI Ý VÀ HỌC CÂU MỚI (Giữ nguyên như cũ)
// =================================================================
function runHint() {
    const panel = document.querySelector('.question-panel');
    if (!panel || panel.classList.contains('question-panel--correct') || panel.classList.contains('question-panel--incorrect')) return;

    const qEl = panel.querySelector('.question-content .content-display');
    if (!qEl) return;
    
    const qText = qEl.innerText.trim();
    // Đọc thẳng từ kho vừa mix ở trên
    const data = JSON.parse(localStorage.getItem('quiz_answers') || '[]');
    const match = data.find(x => x.question === qText || qText.includes(x.question));

    if (match) {
        const answers = panel.querySelectorAll('.mc-text-question .display-panel > div');
        answers.forEach(ans => {
            const label = ans.querySelector('label');
            if (label) {
                const text = label.innerText.replace(/\[\.\]/g, '').trim(); 
                let isCorrect = match.correct_answers ? match.correct_answers.includes(text) : (match.correct_answer === text);

                if (isCorrect) {
                    if (!label.querySelector('.lms-hint-dot')) {
                        // Thêm dấu [.] màu đỏ
                        label.innerHTML += ' <span class="lms-hint-dot" style="color: #ff4d4f; font-weight: bold; margin-left: 5px;">[.]</span>';
                    }
                }
            }
        });
    }
}

function runSave() {
    const panel = document.querySelector('.question-panel--correct, .question-panel--incorrect');
    if (!panel) return;

    const qEl = panel.querySelector('.question-content .content-display');
    const aEls = panel.querySelectorAll('.default-match label');

    if (qEl && aEls.length > 0) {
        const qText = qEl.innerText.trim();
        const aTexts = Array.from(aEls).map(el => el.innerText.trim());

        let data = JSON.parse(localStorage.getItem('quiz_answers') || '[]');
        if (!data.find(x => x.question === qText)) {
            data.push({ question: qText, correct_answers: aTexts });
            localStorage.setItem('quiz_answers', JSON.stringify(data));
            console.log("💾 Đã học thêm 1 câu mới vào kho!");
        }
    }
}

// Chạy ngầm Observer
if (!window.lmsObserverEnabled) {
    const lmsObserver = new MutationObserver((mutations) => {
        for (let mutation of mutations) {
            if (mutation.type === 'childList' || mutation.type === 'attributes') {
                runHint();
                runSave();
                break;
            }
        }
    });

    lmsObserver.observe(document.body, { childList: true, subtree: true, attributes: true, attributeFilter: ['class'] });
    window.lmsObserverEnabled = true;
}